VS Code extension that auto-fixes Tailwind CSS canonical class diagnostics on save.

```json title="package.json"
{
  "name": "tailwind-canonical-classes-autofix",
  "displayName": "Tailwind Canonical Classes Autofix",
  "description": "Auto-fix Tailwind CSS canonical class suggestions from Tailwind CSS IntelliSense diagnostics on save.",
  "version": "0.1.0",
  "publisher": "local-dev",
  "engines": {
    "vscode": "^1.90.0"
  },
  "activationEvents": [
    "onLanguage:html",
    "onLanguage:typescriptreact",
    "onLanguage:javascriptreact"
  ],
  "main": "./dist/extension.js",
  "contributes": {
    "configuration": {
      "title": "Tailwind Canonical Classes",
      "properties": {
        "tailwindCanonicalClasses.fixOnSave": {
          "type": "boolean",
          "default": true,
          "description": "Apply canonical Tailwind CSS class fixes before save."
        }
      }
    }
  },
  "scripts": {
    "compile": "tsc -p ./",
    "test": "vitest run"
  },
  "devDependencies": {
    "@types/vscode": "^1.90.0",
    "typescript": "^5.5.3",
    "vitest": "^2.1.1"
  }
}
